import { async } from "@firebase/util"
import { getRedirectResult } from "firebase/auth"
import { useEffect } from "react"
import { 
    auth,
    signInWithGooglePopup,
    signInWithGoogleRedirect,
    createUserDocumentFromAuth, 
} from "../../utils/firebase/firebase.utils"

const SignIn = ()=>{
    useEffect(() => {
        async function tempFunc(auth){
            const response = await getRedirectResult(auth)
            return response
        }
        tempFunc(auth).then(async(response)=>{
            if(response){
                const userDocRef = await createUserDocumentFromAuth(response.user)
            }
        })
        userDocRef = null
    },[])

    const logGoogleRedirectUser = async () => {
        await signInWithGoogleRedirect()
    }

    const logGoogleUser = async() =>{
        const {user} = await signInWithGooglePopup()
        createUserDocumentFromAuth(user)
    }
    return(
        <div>
            <h1>sign-in</h1>
            <button onClick={logGoogleUser}>Sign In With Google Account</button>
            <button onClick={logGoogleRedirectUser}>Sign In With Google Account Redirect</button>
        </div>
    )
}

export default SignIn
